script:
export const meta = {
  name: 'cleanup_tus',
  description: 'Apply R1-R8 cleanup to one or more FULL_MATCH translation units',
}

const tuList = (args && args.tus) || []
const onlyComments = (args && args.onlyComments) || false

if (!tuList.length) {
  log('No TUs provided in args.tus')
  return { status: 'skipped', reason: 'no tus' }
}

log(`Cleaning ${tuList.length} TUs (onlyComments=${onlyComments})`)

const tu = (unit, file, desc) => () => agent(
  (onlyComments
    ? `Add R8 comments to FULL_MATCH TU: ${unit}

Source: ${file}

FOCUS ON R8 ONLY. Do NOT change any code or field names.
- Add leading comment blocks to functions 10+ lines (what, why, params, return)
- Add inline comments to non-obvious fields, magic constants, linker symbols
- Small helpers/trivial wrappers skip comments
- R7: verify build+diff+size after edits, no regressions

${desc}`
    : `Clean up FULL_MATCH TU: ${unit}

Source: ${file}

Apply ALL rules (R1-R8) to ALL FULL_MATCH functions:
- R1: NO void pointers
- R2: NO pointer arithmetic
- R3: NO void types
- R4: Proper classes/structs
- R5: Human-friendly names for fields, vars, params
- R6: Create headers if missing
- R7: Never regress — build+diff+size after EVERY edit
- R8: Comments on functions 10+ lines and non-obvious fields

${desc}`),
  { agent: 'cleanup', agentScope: 'both', confirmProjectAgents: false }
)

const results = await parallel(tuList.map(t => () => tu(t.unit, t.file, t.desc || '')))

return { processed: tuList.length, results }
